import { useCallback, useEffect, useRef, useState } from 'react';
import { HeroAvatar } from './HeroAvatar';
import { usePartyPrefs } from '../hooks/usePartyPrefs';
import type { AgentState } from '../types/agent';
import './PartyBar.css';

interface PartyBarProps {
  agents: AgentState[];
  selectedAgentId: string | null;
  onSelectAgent: (id: string | null) => void;
}

const AVATAR_SIZE = 66;
const FLASH_DURATION_MS = 400;

const STATUS_ORDER: Record<AgentState['status'], number> = {
  active: 0,
  waiting: 1,
  idle: 2,
  error: 3,
  completed: 4,
};

interface PartyRowProps {
  agent: AgentState;
  mode: 'full' | 'icons';
  isSelected: boolean;
  onClick: () => void;
}

function PartyRow({ agent, mode, isSelected, onClick }: PartyRowProps) {
  const [flashing, setFlashing] = useState(false);
  const prevSelected = useRef(isSelected);

  useEffect(() => {
    if (!prevSelected.current && isSelected) {
      setFlashing(true);
      const id = setTimeout(() => setFlashing(false), FLASH_DURATION_MS);
      prevSelected.current = isSelected;
      return () => clearTimeout(id);
    }
    prevSelected.current = isSelected;
  }, [isSelected]);

  const classes = [
    'partybar-agent',
    `mode-${mode}`,
    isSelected ? 'selected' : '',
    flashing ? 'flashing' : '',
  ].filter(Boolean).join(' ');

  const title = mode === 'icons'
    ? `${agent.name} · ${agent.currentActivity}`
    : undefined;

  return (
    <button
      type="button"
      className={classes}
      onClick={onClick}
      aria-label={`Select ${agent.name}, ${agent.currentActivity}`}
      aria-current={isSelected ? 'true' : undefined}
      title={title}
    >
      <span className="partybar-avatar-wrap">
        <HeroAvatar agent={agent} size={AVATAR_SIZE} />
        <span className={`partybar-status-overlay ${agent.status}`} aria-hidden="true" />
      </span>
      {mode === 'full' && (
        <span className="partybar-row-body">
          <span className="partybar-row-top">
            <span className="partybar-agent-name">{agent.name}</span>
            <span className={`partybar-dot ${agent.status}`} aria-hidden="true" />
          </span>
          <span className="partybar-activity">{agent.currentActivity}</span>
        </span>
      )}
    </button>
  );
}

export function PartyBar({ agents, selectedAgentId, onSelectAgent }: PartyBarProps) {
  const [prefs, updatePrefs] = usePartyPrefs();
  const mode: 'full' | 'icons' = prefs.foldState;

  const visible = agents.filter((a) => a.status === 'active' || a.status === 'idle');
  const sorted = [...visible].sort((a, b) => STATUS_ORDER[a.status] - STATUS_ORDER[b.status]);
  const activeCount = visible.filter((a) => a.status === 'active').length;
  const idleCount = visible.filter((a) => a.status === 'idle').length;

  const toggleFold = useCallback(() => {
    updatePrefs({ foldState: mode === 'full' ? 'icons' : 'full' });
  }, [mode, updatePrefs]);

  const handleClick = useCallback((id: string) => {
    onSelectAgent(id);
  }, [onSelectAgent]);

  return (
    <div className={`partybar mode-${mode}`} role="list" aria-label="Party">
      <div className="partybar-header">
        {mode === 'full' ? (
          <span className="partybar-title">Party ({activeCount} active, {idleCount} idle)</span>
        ) : (
          <span className="partybar-title-compact">{activeCount + idleCount}</span>
        )}
        <button
          type="button"
          className="partybar-fold-btn"
          aria-label={mode === 'full' ? 'Collapse to icons' : 'Expand party'}
          aria-pressed={mode === 'icons'}
          onClick={toggleFold}
        >{mode === 'full' ? '◀' : '▶'}</button>
      </div>

      <div className="partybar-list">
        {sorted.map((agent) => (
          <PartyRow
            key={agent.id}
            agent={agent}
            mode={mode}
            isSelected={agent.id === selectedAgentId}
            onClick={() => handleClick(agent.id)}
          />
        ))}
      </div>
    </div>
  );
}

import { memo, useCallback, useEffect, useState, type ReactNode } from 'react';
import ReactMarkdown from 'react-markdown';
import { HERO_LABEL_COLOR, type ActivityLogEntry, type AgentState } from '../types/agent';
import { HeroAvatar } from './HeroAvatar';
import { isError, isPath, resolvePath, categorizeEntry } from './activityFeedUtils';
import type { ActionFilter } from './activityFeedUtils';

// Message cells render detail as markdown (bold, italic, code, links). The
// custom `p` renderer emits a fragment so multiple paragraphs flow inline —
// no extra vertical space, no visible paragraph breaks.
const MD_COMPONENTS = {
  p: ({ children }: { children?: ReactNode }) => <>{children}</>,
};

interface ActivityRowProps {
  entry: ActivityLogEntry;
  agent: AgentState | undefined;
  agentName: string;
  /** When true, hides the avatar+name (used inside AgentGroup). */
  inGroup?: boolean;
  highlighted: boolean;
  isSelected: boolean;
  onSelectAgent: (id: string) => void;
  onFilterAgent: (id: string) => void;
}

interface MenuState {
  x: number;
  y: number;
}

function ActivityRowImpl({
  entry, agent, agentName, inGroup, highlighted, isSelected,
  onSelectAgent, onFilterAgent,
}: ActivityRowProps) {
  const [menu, setMenu] = useState<MenuState | null>(null);
  const error = isError(entry.action, entry.detail);
  const isMessage = entry.action === 'Reply' || entry.action === 'Prompt';
  const detailIsPath = !isMessage && isPath(entry.detail);
  const absolute = detailIsPath ? resolvePath(entry.detail, agent?.cwd) : null;
  const pillVariant = entry.action === 'Reply' ? 'is-reply' : entry.action === 'Prompt' ? 'is-prompt' : '';
  const category: ActionFilter = categorizeEntry(entry.action, entry.detail);
  const time = new Date(entry.timestamp).toLocaleTimeString('en-US', {
    hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit',
  });

  const onContextMenu = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    setMenu({ x: e.clientX, y: e.clientY });
  }, []);

  const closeMenu = useCallback(() => setMenu(null), []);

  const copy = useCallback((text: string) => {
    void navigator.clipboard.writeText(text).catch(() => { /* permissions; ignore */ });
    closeMenu();
  }, [closeMenu]);

  const rowClasses = [
    'feed-entry',
    error ? 'is-error' : '',
    isMessage ? 'is-message' : '',
    highlighted ? `is-highlighted hl-${category}` : '',
    isSelected ? 'is-selected' : '',
  ].filter(Boolean).join(' ');

  return (
    <div className={rowClasses} onContextMenu={onContextMenu} role="listitem">
      {!inGroup && agent !== undefined && (
        <button
          type="button"
          className="feed-row-avatar"
          aria-label={`Select agent ${agentName}`}
          onClick={() => onSelectAgent(agent.id)}
        >
          <HeroAvatar agent={agent} size="inherit" />
        </button>
      )}

      <div className="feed-row-body">
        <div className="feed-row-meta">
          {!inGroup && agent !== undefined && (
            <button
              type="button"
              className="feed-agent-name"
              aria-label={`Filter feed to ${agentName}`}
              onClick={() => onFilterAgent(agent.id)}
              title={agentName}
              style={{ color: HERO_LABEL_COLOR[agent.heroColor] }}
            >{agentName}</button>
          )}
          <span className={`feed-action-pill ${error ? 'is-error' : ''} ${pillVariant}`}>{entry.action}</span>
          <span className="feed-time">{time}</span>
        </div>
        {isMessage ? (
          <div className={`feed-detail is-message ${pillVariant}`}>
            <ReactMarkdown components={MD_COMPONENTS}>{entry.detail}</ReactMarkdown>
          </div>
        ) : detailIsPath && absolute !== null ? (
          <a
            href={`vscode://file${encodeURI(absolute)}`}
            className="feed-detail is-path"
            title={entry.detail}
          >{entry.detail}</a>
        ) : (
          <span className={`feed-detail ${detailIsPath ? 'is-path-unresolved' : ''}`} title={entry.detail}>
            {entry.detail}
          </span>
        )}
      </div>

      {menu !== null && (
        <ContextMenu
          x={menu.x}
          y={menu.y}
          onClose={closeMenu}
          actions={[
            { label: 'Copy path', onClick: () => copy(absolute ?? entry.detail), enabled: detailIsPath },
            { label: 'Copy detail', onClick: () => copy(entry.detail), enabled: true },
            { label: 'Filter to this agent', onClick: () => { if (agent !== undefined) onFilterAgent(agent.id); closeMenu(); }, enabled: agent !== undefined },
          ]}
        />
      )}
    </div>
  );
}

interface ContextMenuProps {
  x: number;
  y: number;
  onClose: () => void;
  actions: { label: string; onClick: () => void; enabled: boolean }[];
}

function ContextMenu({ x, y, onClose, actions }: ContextMenuProps) {
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [onClose]);

  return (
    <>
      <div className="feed-menu-overlay" onClick={onClose} onContextMenu={(e) => { e.preventDefault(); onClose(); }} />
      <ul className="feed-menu" style={{ left: x, top: y }} role="menu">
        {actions.filter((a) => a.enabled).map((a) => (
          <li key={a.label} role="menuitem">
            <button type="button" onClick={a.onClick}>{a.label}</button>
          </li>
        ))}
      </ul>
    </>
  );
}

// Callbacks (onSelectAgent, onFilterAgent) intentionally omitted from the
// comparator — the parent must memoize them (useCallback) so their identity
// stays stable across renders, otherwise stale closures can fire.
export const ActivityRow = memo(ActivityRowImpl, (prev, next) =>
  prev.entry.timestamp === next.entry.timestamp &&
  prev.entry.agentId  === next.entry.agentId  &&
  prev.entry.action   === next.entry.action   &&
  prev.entry.detail   === next.entry.detail   &&
  prev.agentName      === next.agentName      &&
  prev.agent?.id      === next.agent?.id      &&
  prev.agent?.cwd     === next.agent?.cwd     &&
  prev.agent?.heroClass === next.agent?.heroClass &&
  prev.agent?.heroColor === next.agent?.heroColor &&
  prev.inGroup        === next.inGroup        &&
  prev.highlighted    === next.highlighted    &&
  prev.isSelected     === next.isSelected
);

import { useCallback, useEffect, useRef, useState } from 'react';
import type { ActionFilter } from '../components/activityFeedUtils';

export type FoldState = 'full' | 'compact' | 'closed';
export type ViewMode = 'all' | 'byAgent';

export interface FeedPrefs {
  foldState: FoldState;
  viewMode: ViewMode;
  activeHighlights: ActionFilter[];
  agentFilter: string | null;
}

export const DEFAULT_PREFS: FeedPrefs = {
  foldState: 'full',
  viewMode: 'all',
  activeHighlights: [],
  agentFilter: null,
};

const STORAGE_KEY = 'agentquest:activityFeed:prefs';
const WRITE_DEBOUNCE_MS = 200;

const FOLD_STATES: FoldState[] = ['full', 'compact', 'closed'];
const VIEW_MODES: ViewMode[] = ['all', 'byAgent'];
const FILTERS: ActionFilter[] = ['errors', 'edits', 'bash', 'reads', 'messages', 'agent', 'other'];

function isFoldState(v: unknown): v is FoldState {
  return typeof v === 'string' && (FOLD_STATES as string[]).includes(v);
}
function isViewMode(v: unknown): v is ViewMode {
  return typeof v === 'string' && (VIEW_MODES as string[]).includes(v);
}
function isFilter(v: unknown): v is ActionFilter {
  return typeof v === 'string' && (FILTERS as string[]).includes(v);
}

export function parsePrefs(raw: string | null): FeedPrefs {
  if (raw === null) return DEFAULT_PREFS;
  let obj: unknown;
  try { obj = JSON.parse(raw); } catch { return DEFAULT_PREFS; }
  if (obj === null || typeof obj !== 'object') return DEFAULT_PREFS;
  const o = obj as Record<string, unknown>;
  const highlightsRaw = Array.isArray(o.activeHighlights)
    ? o.activeHighlights
    : Array.isArray(o.activeFilters)
      ? o.activeFilters
      : null;
  return {
    foldState: isFoldState(o.foldState) ? o.foldState : DEFAULT_PREFS.foldState,
    viewMode: isViewMode(o.viewMode) ? o.viewMode : DEFAULT_PREFS.viewMode,
    activeHighlights: highlightsRaw !== null
      ? highlightsRaw.filter(isFilter)
      : DEFAULT_PREFS.activeHighlights,
    agentFilter: typeof o.agentFilter === 'string' && o.agentFilter.length > 0
      ? o.agentFilter
      : null,
  };
}

export function mergePrefs(base: FeedPrefs, patch: Partial<FeedPrefs>): FeedPrefs {
  return { ...base, ...patch };
}

export function useFeedPrefs(): [FeedPrefs, (patch: Partial<FeedPrefs>) => void] {
  const [prefs, setPrefs] = useState<FeedPrefs>(() => {
    if (typeof window === 'undefined') return DEFAULT_PREFS;
    return parsePrefs(window.localStorage.getItem(STORAGE_KEY));
  });

  const writeTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const pendingValue = useRef<FeedPrefs | null>(null);

  useEffect(() => {
    if (writeTimer.current !== null) clearTimeout(writeTimer.current);
    pendingValue.current = prefs;
    writeTimer.current = setTimeout(() => {
      try {
        window.localStorage.setItem(STORAGE_KEY, JSON.stringify(prefs));
      } catch { /* quota or private mode — silently ignore */ }
      pendingValue.current = null;
    }, WRITE_DEBOUNCE_MS);
    return () => {
      if (writeTimer.current !== null) clearTimeout(writeTimer.current);
    };
  }, [prefs]);

  // Flush pending write on unmount so a fast close/navigation doesn't lose the
  // last user change. Separate effect keeps the debounce loop above clean.
  useEffect(() => {
    return () => {
      if (pendingValue.current !== null) {
        try {
          window.localStorage.setItem(STORAGE_KEY, JSON.stringify(pendingValue.current));
        } catch { /* quota or private mode — silently ignore */ }
        pendingValue.current = null;
      }
    };
  }, []);

  const update = useCallback((patch: Partial<FeedPrefs>) => {
    setPrefs((prev) => mergePrefs(prev, patch));
  }, []);

  return [prefs, update];
}

import { useCallback, useEffect, useRef, useState } from 'react';

export type PartyFoldState = 'full' | 'icons';

export interface PartyPrefs {
  foldState: PartyFoldState;
}

export const DEFAULT_PARTY_PREFS: PartyPrefs = {
  foldState: 'full',
};

const STORAGE_KEY = 'agentquest:partyBar:prefs';
const WRITE_DEBOUNCE_MS = 200;

const FOLD_STATES: PartyFoldState[] = ['full', 'icons'];

function isPartyFoldState(v: unknown): v is PartyFoldState {
  return typeof v === 'string' && (FOLD_STATES as string[]).includes(v);
}

export function parsePartyPrefs(raw: string | null): PartyPrefs {
  if (raw === null) return DEFAULT_PARTY_PREFS;
  let obj: unknown;
  try { obj = JSON.parse(raw); } catch { return DEFAULT_PARTY_PREFS; }
  if (obj === null || typeof obj !== 'object') return DEFAULT_PARTY_PREFS;
  const o = obj as Record<string, unknown>;
  return {
    foldState: isPartyFoldState(o.foldState) ? o.foldState : DEFAULT_PARTY_PREFS.foldState,
  };
}

export function mergePartyPrefs(base: PartyPrefs, patch: Partial<PartyPrefs>): PartyPrefs {
  return { ...base, ...patch };
}

export function usePartyPrefs(): [PartyPrefs, (patch: Partial<PartyPrefs>) => void] {
  const [prefs, setPrefs] = useState<PartyPrefs>(() => {
    if (typeof window === 'undefined') return DEFAULT_PARTY_PREFS;
    return parsePartyPrefs(window.localStorage.getItem(STORAGE_KEY));
  });

  const writeTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const pendingValue = useRef<PartyPrefs | null>(null);

  useEffect(() => {
    if (writeTimer.current !== null) clearTimeout(writeTimer.current);
    pendingValue.current = prefs;
    writeTimer.current = setTimeout(() => {
      try {
        window.localStorage.setItem(STORAGE_KEY, JSON.stringify(prefs));
      } catch { /* quota or private mode — silently ignore */ }
      pendingValue.current = null;
    }, WRITE_DEBOUNCE_MS);
    return () => {
      if (writeTimer.current !== null) clearTimeout(writeTimer.current);
    };
  }, [prefs]);

  useEffect(() => {
    return () => {
      if (pendingValue.current !== null) {
        try {
          window.localStorage.setItem(STORAGE_KEY, JSON.stringify(pendingValue.current));
        } catch { /* quota or private mode — silently ignore */ }
        pendingValue.current = null;
      }
    };
  }, []);

  const update = useCallback((patch: Partial<PartyPrefs>) => {
    setPrefs((prev) => mergePartyPrefs(prev, patch));
  }, []);

  return [prefs, update];
}

import { useEffect, useState, useCallback } from 'react';
import { PhaserGame } from './game/PhaserGame';
import { useAgentState } from './hooks/useAgentState';
import { useSelectedAgent } from './hooks/useSelectedAgent';
import { eventBridge } from './game/EventBridge';
import { TopBar } from './components/TopBar';
import { PartyBar } from './components/PartyBar';
import { ActivityFeed } from './components/ActivityFeed';
import { DetailPanel } from './components/DetailPanel';
import { BuildingInfoPanel } from './components/BuildingInfoPanel';
import { Tutorial } from './components/Tutorial';
import { NoClaudeBanner } from './components/NoClaudeBanner';
import './App.css';

export default function App() {
  const { agents, activityLog, connected, configDirs } = useAgentState();
  const { selectedAgentId, selectAgent } = useSelectedAgent();
  const [selectedBuildingId, setSelectedBuildingId] = useState<string | null>(null);
  const [villageReady, setVillageReady] = useState(false);
  const [tutorialOpen, setTutorialOpen] = useState(false);

  const closeTutorial = useCallback(() => {
    setTutorialOpen(false);
    try { localStorage.setItem('agent-quest:tutorial-seen', '1'); } catch {}
  }, []);

  const selectedAgent = selectedAgentId !== null
    ? agents.find((a) => a.id === selectedAgentId) ?? null
    : null;

  // When selecting agent, clear building
  const handleSelectAgent = useCallback((id: string | null) => {
    selectAgent(id);
    setSelectedBuildingId(null);
  }, [selectAgent]);

  // When selecting building, clear agent
  const handleSelectBuilding = useCallback((id: string) => {
    setSelectedBuildingId((prev) => (prev === id ? null : id));
    selectAgent(null);
  }, [selectAgent]);

  // Listen for building clicks from Phaser
  useEffect(() => {
    const onBuildingClicked = (id: unknown) => {
      handleSelectBuilding(id as string);
    };
    eventBridge.on('building:clicked', onBuildingClicked);
    return () => {
      eventBridge.off('building:clicked', onBuildingClicked);
    };
  }, [handleSelectBuilding]);

  // Listen for hero clicks from Phaser. String = select that agent;
  // null = user clicked the map background with no hero hit → deselect.
  useEffect(() => {
    const onHeroClicked = (id: unknown) => {
      if (id === null) handleSelectAgent(null);
      else if (typeof id === 'string') handleSelectAgent(id);
    };
    eventBridge.on('hero:clicked', onHeroClicked);
    return () => {
      eventBridge.off('hero:clicked', onHeroClicked);
    };
  }, [handleSelectAgent]);

  // Hide the HTML overlays (TopBar, PartyBar, etc.) while the BootScene is up.
  // VillageScene emits 'village:ready' in its create().
  useEffect(() => {
    const onReady = () => {
      setVillageReady(true);
      try {
        if (localStorage.getItem('agent-quest:tutorial-seen') !== '1') {
          setTutorialOpen(true);
        }
      } catch {
        setTutorialOpen(true);
      }
    };
    eventBridge.on('village:ready', onReady);
    return () => eventBridge.off('village:ready', onReady);
  }, []);

  useEffect(() => {
    const onOpen = () => setTutorialOpen(true);
    eventBridge.on('tutorial:open', onOpen);
    return () => eventBridge.off('tutorial:open', onOpen);
  }, []);

  useEffect(() => {
    eventBridge.emit('agents:updated', agents);
  }, [agents]);

  useEffect(() => {
    eventBridge.emit('selection:changed', selectedAgentId);
  }, [selectedAgentId]);

  useEffect(() => {
    if (connected) {
      eventBridge.emit('ws:connected');
    } else {
      eventBridge.emit('ws:disconnected');
    }
  }, [connected]);

  return (
    <div className="app-container">
      <PhaserGame />
      {villageReady && (
        <div className="overlay">
          <TopBar agents={agents} connected={connected} />
          <NoClaudeBanner configDirs={configDirs} connected={connected} />
          <PartyBar
            agents={agents}
            selectedAgentId={selectedAgentId}
            onSelectAgent={handleSelectAgent}
          />
          {selectedAgent !== null && (
            <DetailPanel agent={selectedAgent} onClose={() => handleSelectAgent(null)} />
          )}
          {selectedBuildingId !== null && (
            <BuildingInfoPanel
              buildingId={selectedBuildingId}
              agents={agents}
              onClose={() => setSelectedBuildingId(null)}
            />
          )}
          <ActivityFeed
            log={activityLog}
            agents={agents}
            selectedAgentId={selectedAgentId}
            onSelectAgent={handleSelectAgent}
          />
        </div>
      )}
      {tutorialOpen && <Tutorial onClose={closeTutorial} />}
    </div>
  );
}

import * as Phaser from 'phaser';
import { HERO_LABEL_COLOR, type HeroClass, type HeroColor, type AgentActivity, type AgentState } from '../../types/agent';
import { getActiveTheme } from '../themes/registry';
import { findRoadPath, type Point } from '../data/road-network';
import { addCrispText } from '../text';

const MOVE_SPEED = 150;
/** Ground distance covered by one full run-cycle. Keeps legs synced to travel. */
const RUN_PIXELS_PER_CYCLE = 60;

/**
 * Label offsets are computed per-instance from the sprite's actual
 * displayHeight so they adapt to whatever scale the active theme uses.
 * The formulas below reproduce the original Tiny Swords values
 * (sprite 96 px → name -50, activity +46, detail +60, task +74).
 */
const TASK_MAX_CHARS = 28;

const ACTIVITY_COLOR: Record<AgentActivity, string> = {
  idle:      '#888888',
  thinking:  '#C48BE8',
  reading:   '#88BBFF',
  editing:   '#FFD27A',
  bash:      '#FF9966',
  git:       '#88E08A',
  debugging: '#FF6B6B',
  reviewing: '#7AE0C8',
};

const WAITING_COLOR = '#FFD700';
const ERROR_COLOR = '#FF4444';
const ERROR_WINDOW_MS = 90 * 1000;

const HALO_TEXTURE_KEY = 'hero-selection-halo';

/**
 * Lazily build a soft radial-gradient texture we can reuse as the selection
 * halo. Generated once per scene; subsequent callers hit the texture cache.
 * The gradient fades white → transparent so the glow blends with the scene
 * instead of looking like a flat disc.
 */
function ensureHaloTexture(scene: Phaser.Scene): void {
  if (scene.textures.exists(HALO_TEXTURE_KEY)) return;
  const size = 128;
  const tex = scene.textures.createCanvas(HALO_TEXTURE_KEY, size, size);
  if (tex === null) return;
  const ctx = tex.getContext();
  const cx = size / 2;
  const cy = size / 2;
  const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, cx);
  grad.addColorStop(0.00, 'rgba(255, 255, 255, 0.9)');
  grad.addColorStop(0.35, 'rgba(255, 255, 255, 0.45)');
  grad.addColorStop(0.70, 'rgba(255, 255, 255, 0.12)');
  grad.addColorStop(1.00, 'rgba(255, 255, 255, 0.0)');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, size, size);
  tex.refresh();
}

export class HeroSprite {
  readonly id: string;
  readonly heroClass: HeroClass;
  private scene: Phaser.Scene;
  private sprite: Phaser.GameObjects.Sprite;
  private nameText: Phaser.GameObjects.Text;
  private subagentText: Phaser.GameObjects.Text | null = null;
  private activityText: Phaser.GameObjects.Text;
  private detailText: Phaser.GameObjects.Text;
  private taskText: Phaser.GameObjects.Text;
  private _x: number;
  private _y: number;
  private moveTween: Phaser.Tweens.Tween | null = null;
  private waitingTween: Phaser.Tweens.Tween | null = null;
  private errorTimer: Phaser.Time.TimerEvent | null = null;
  private idleKey: string;
  private runKey: string;
  private facesLeft: boolean;
  private nameOffsetY: number;
  private subagentOffsetY: number;
  private activityOffsetY: number;
  private detailOffsetY: number;
  private taskOffsetY: number;
  currentActivity: AgentActivity = 'idle';
  private isWaiting = false;
  private isErrorRecent = false;
  private nameBaseColor = '#DDDDDD';
  private selectionTween: Phaser.Tweens.Tween | null = null;
  private selectionHalo: Phaser.GameObjects.Image | null = null;

  /** Grid base position — used for slot repositioning. */
  gridBaseX = 0;
  gridBaseY = 0;

  constructor(
    scene: Phaser.Scene,
    id: string,
    name: string,
    heroClass: HeroClass,
    heroColor: HeroColor,
    x: number,
    y: number,
    isSubagent = false,
  ) {
    this.scene = scene;
    this.id = id;
    this.heroClass = heroClass;
    this._x = x;
    this._y = y;

    const theme = getActiveTheme();
    const cfg = theme.getHeroConfig(heroColor, heroClass);
    this.idleKey = cfg.idleKey;
    this.runKey = cfg.runKey;
    this.facesLeft = cfg.facesLeft;

    // Create sprite with idle animation
    this.sprite = scene.add.sprite(x, y, this.idleKey);
    this.sprite.setScale(theme.heroScale);
    // Flip sprites that natively face left so they face right by default
    this.sprite.setFlipX(this.facesLeft);
    if (cfg.tint !== null) this.sprite.setTint(cfg.tint);

    // Label offsets derived from actual sprite height — scale with theme.
    const halfH = this.sprite.displayHeight / 2;
    this.nameOffsetY = -(halfH + 2);
    // Subagent marker sits ~11px below the name (standard "subtitle" placement,
    // so the name stays the primary anchor for the eye).
    this.subagentOffsetY = this.nameOffsetY + 11;
    this.activityOffsetY = halfH - 2;
    this.detailOffsetY = halfH + 12;
    this.taskOffsetY = halfH + 26;

    // Create idle animation if it doesn't exist yet
    const idleAnimKey = `${this.idleKey}-anim`;
    if (!scene.anims.exists(idleAnimKey)) {
      const idleFrameSpec = cfg.idleFrameIndices !== undefined
        ? { frames: cfg.idleFrameIndices }
        : { start: 0, end: cfg.idleFrames - 1 };
      scene.anims.create({
        key: idleAnimKey,
        frames: scene.anims.generateFrameNumbers(this.idleKey, idleFrameSpec),
        frameRate: cfg.idleFrames > 1 ? 8 : 1,
        repeat: -1,
      });
    }

    const runAnimKey = `${this.runKey}-anim`;
    if (!scene.anims.exists(runAnimKey)) {
      // Match frame rate to ground speed so legs don't float or drag.
      const runFrameRate = cfg.runFrames * (MOVE_SPEED / RUN_PIXELS_PER_CYCLE);
      const runFrameSpec = cfg.runFrameIndices !== undefined
        ? { frames: cfg.runFrameIndices }
        : { start: 0, end: cfg.runFrames - 1 };
      scene.anims.create({
        key: runAnimKey,
        frames: scene.anims.generateFrameNumbers(this.runKey, runFrameSpec),
        frameRate: runFrameRate,
        repeat: -1,
      });
    }

    this.sprite.play(idleAnimKey);

    const nameColor = HERO_LABEL_COLOR[heroColor] ?? '#DDDDDD';
    this.nameBaseColor = nameColor;
    this.nameText = addCrispText(scene, x, y + this.nameOffsetY, name, {
      fontSize: '14px',
      color: nameColor,
      fontFamily: 'monospace',
      stroke: '#000000',
      strokeThickness: 3,
    }).setOrigin(0.5);

    // Subagent marker: only created for spawned subagents — sits just above
    // the name to visually distinguish child heroes from parent sessions.
    if (isSubagent) {
      this.subagentText = addCrispText(scene, x, y + this.subagentOffsetY, 'subagent', {
        fontSize: '9px',
        color: '#9AA4B0',
        fontFamily: 'monospace',
        fontStyle: 'italic',
        stroke: '#000000',
        strokeThickness: 2,
      }).setOrigin(0.5);
    }

    // Activity label below hero
    this.activityText = addCrispText(scene, x, y + this.activityOffsetY, 'idle', {
      fontSize: '12px',
      color: ACTIVITY_COLOR.idle,
      fontFamily: 'monospace',
      stroke: '#000000',
      strokeThickness: 2,
    }).setOrigin(0.5);

    // Detail label (file/command) below activity
    this.detailText = addCrispText(scene, x, y + this.detailOffsetY, '', {
      fontSize: '11px',
      color: '#AABBCC',
      fontFamily: 'monospace',
      stroke: '#000000',
      strokeThickness: 2,
    }).setOrigin(0.5);

    // Task label (current user prompt) below detail
    this.taskText = addCrispText(scene, x, y + this.taskOffsetY, '', {
      fontSize: '10px',
      color: '#9FB7D4',
      fontFamily: 'monospace',
      fontStyle: 'italic',
      stroke: '#000000',
      strokeThickness: 2,
    }).setOrigin(0.5);

    // Set initial Y-based depth
    this.updateDepth();
  }

  get x(): number { return this._x; }
  get y(): number { return this._y; }

  /** Override the default hero scale (e.g. from MapConfig settings). */
  setHeroScale(scale: number): void {
    this.sprite.setScale(scale);
  }

  /** Make the sprite respond to pointerdown with the supplied callback. */
  setInteractiveForSelection(onClick: () => void): void {
    if (!this.sprite.input || !this.sprite.input.enabled) {
      this.sprite.setInteractive({ useHandCursor: true });
    }
    // Tag unconditionally so the scene-level background click detector can
    // recognize a hero hit regardless of the setInteractive branch above.
    this.sprite.setData('isHero', true);
    this.sprite.on('pointerdown', onClick);
  }

  /**
   * Apply or clear a selection visual: a pulsing blue halo BEHIND the sprite
   * (alpha + scale yoyo ~1s cycle). The sprite itself stays untinted so the
   * character's natural colors are preserved; only the surrounding light
   * pulses. The name text is brightened so the selected hero's label stands
   * out against its neighbors.
   */
  setSelected(selected: boolean): void {
    if (this.selectionTween !== null) {
      this.selectionTween.stop();
      this.selectionTween = null;
    }
    if (this.selectionHalo !== null) {
      this.selectionHalo.destroy();
      this.selectionHalo = null;
    }
    if (selected) {
      ensureHaloTexture(this.scene);
      const diameter = Math.max(this.sprite.displayWidth, this.sprite.displayHeight) * 1.1;
      const halo = this.scene.add.image(this._x, this._y, HALO_TEXTURE_KEY);
      halo.setDisplaySize(diameter, diameter);
      halo.setAlpha(0.35);
      halo.setDepth(this.sprite.depth - 0.1);

import * as Phaser from 'phaser';
import { eventBridge } from '../EventBridge';
import { Building } from '../entities/Building';
import { HeroSprite } from '../entities/HeroSprite';
